sys_hub_flow.flow_definition:
{
  "version": "1.0",
  "steps": [
    {
      "id": "step_1",
      "type": "action",
      "name": "Get Assigned User Details",
      "description": "Look up the sys_user record for the assigned team member to retrieve their email address and display name.",
      "action": "com.glide.platform_actions.look_up_record",
      "inputs": {
        "table": "sys_user",
        "filter": "sys_id={{trigger.record.assigned_to.sys_id}}"
      },
      "outputs": {
        "assigned_user": "{{step_1.record}}"
      }
    },
    {
      "id": "step_2",
      "type": "action",
      "name": "Send Task Assigned Email Notification",
      "description": "Send the 'Task Assigned' email notification to the assigned team member using their email address retrieved in Step 1.",
      "action": "com.glide.platform_actions.send_notification",
      "inputs": {
        "notification": "x_ptms_task_assigned",
        "record": "{{trigger.record}}",
        "recipients": "{{step_1.assigned_user.email}}"
      }
    }
  ]
}

{
  "version": "1.0",
  "steps": [
    {
      "id": "step_1",
      "type": "action",
      "name": "Get All Project Managers",
      "description": "Look up all active users who have the x_ptms.project_manager role. This uses a GlideRecord query on sys_user_has_role joined with sys_user.",
      "action": "com.glide.platform_actions.look_up_records",
      "inputs": {
        "table": "sys_user_has_role",
        "filter": "role.name=x_ptms.project_manager^user.active=true",
        "fields": ["user.email", "user.name", "user.sys_id"]
      },
      "outputs": {
        "project_managers": "{{step_1.records}}"
      }
    },
    {
      "id": "step_2",
      "type": "action",
      "name": "Send Task Completed Notification to Project Managers",
      "description": "Send the 'Task Completed' email notification to all Project Manager users identified in Step 1.",
      "action": "com.glide.platform_actions.send_notification",
      "inputs": {
        "notification": "x_ptms_task_completed",
        "record": "{{trigger.record}}",
        "recipients": "{{step_1.project_managers.user.email}}"
      }
    }
  ]
}

{
  "version": "1.0",
  "steps": [
    {
      "id": "step_1",
      "type": "action",
      "name": "Find All Overdue Tasks",
      "description": "Query the x_ptms_project_task table for records where due_date < today AND state != 4 (not Completed).",
      "action": "com.glide.platform_actions.look_up_records",
      "inputs": {
        "table": "x_ptms_project_task",
        "filter": "due_date<javascript:gs.beginningOfToday()^state!=4"
      },
      "outputs": {
        "overdue_tasks": "{{step_1.records}}"
      }
    },
    {
      "id": "step_2",
      "type": "flow_logic",
      "name": "For Each Overdue Task",
      "description": "Iterate over each overdue task record and trigger the overdue notification.",
      "logic": "for_each",
      "inputs": {
        "items": "{{step_1.overdue_tasks}}"
      },
      "inner_steps": [
        {
          "id": "step_2a",
          "type": "action",
          "name": "Send Overdue Notification",
          "description": "Send the 'Task Overdue' notification to the task's assigned user.",
          "action": "com.glide.platform_actions.send_notification",
          "inputs": {
            "notification": "x_ptms_task_overdue",
            "record": "{{step_2.item}}",
            "recipients": "{{step_2.item.assigned_to.email}}"
          }
        }
      ]
    }
  ]
}
